 39→func setupSqlite(db *sql.DB) error {
 40→	pragmas := []string{
 41→		"temp_store = memory",
 42→		"soft_heap_limit = 1073741824", // 1GB process-wide soft limit; SQLite evicts cache pages to stay under
 43→	}
 44→
 45→	for _, pragma := range pragmas {
 46→		_, err := db.Exec("PRAGMA " + pragma)
 47→		if err != nil {
 48→			return err
 49→		}
 50→	}
 51→
 52→	// Update query planner statistics so SQLite picks optimal indexes.
 53→	// Without this, SQLite guesses row distributions and often chooses wrong
 54→	// indexes for queries with IN clauses + ORDER BY, causing full table sorts
 55→	// in temp B-trees instead of using covering indexes.
 56→	if _, err := db.Exec("ANALYZE"); err != nil {
 57→		cclog.Warnf("Failed to run ANALYZE: %v", err)
 58→	}
 59→
 60→	return nil
 61→}
 62→
 63→func Connect(db string) {
 64→	var err error
 65→	var dbHandle *sqlx.DB
 66→
 67→	dbConnOnce.Do(func() {
 68→		opts := DatabaseOptions{
 69→			URL:                   db,
 70→			MaxOpenConnections:    repoConfig.MaxOpenConnections,
 71→			MaxIdleConnections:    repoConfig.MaxIdleConnections,
 72→			ConnectionMaxLifetime: repoConfig.ConnectionMaxLifetime,
 73→			ConnectionMaxIdleTime: repoConfig.ConnectionMaxIdleTime,
 74→		}
 75→
 76→		// TODO: Have separate DB handles for Writes and Reads
 77→		// Optimize SQLite connection: https://kerkour.com/sqlite-for-servers
 78→		connectionURLParams := make(url.Values)
 79→		connectionURLParams.Add("_txlock", "immediate")
 80→		connectionURLParams.Add("_journal_mode", "WAL")
 81→		connectionURLParams.Add("_busy_timeout", "5000")
 82→		connectionURLParams.Add("_synchronous", "NORMAL")
 83→		connectionURLParams.Add("_cache_size", "-200000") // 200MB per connection (negative = KiB)
 84→		connectionURLParams.Add("_foreign_keys", "true")
 85→		opts.URL = fmt.Sprintf("file:%s?%s", opts.URL, connectionURLParams.Encode())
 86→
 87→		if cclog.Loglevel() == "debug" {
 88→			sql.Register("sqlite3WithHooks", sqlhooks.Wrap(&sqlite3.SQLiteDriver{}, &Hooks{}))
 89→			dbHandle, err = sqlx.Open("sqlite3WithHooks", opts.URL)
 90→		} else {
 91→			dbHandle, err = sqlx.Open("sqlite3", opts.URL)
 92→		}
 93→
 94→		if err != nil {
 95→			cclog.Abortf("DB Connection: Could not connect to SQLite database with sqlx.Open().\nError: %s\n", err.Error())
 96→		}
 97→
 98→		err = setupSqlite(dbHandle.DB)
 99→		if err != nil {
100→			cclog.Abortf("Failed sqlite db setup.\nError: %s\n", err.Error())
101→		}
102→
103→		dbHandle.SetMaxOpenConns(opts.MaxOpenConnections)
104→		dbHandle.SetMaxIdleConns(opts.MaxIdleConnections)
105→		dbHandle.SetConnMaxLifetime(opts.ConnectionMaxLifetime)
106→		dbHandle.SetConnMaxIdleTime(opts.ConnectionMaxIdleTime)
107→
108→		dbConnInstance = &DBConnection{DB: dbHandle}
109→		err = checkDBVersion(dbHandle.DB)
110→		if err != nil {
111→			cclog.Abortf("DB Connection: Failed DB version check.\nError: %s\n", err.Error())
112→		}
113→	})
114→}
