170→				return err
171→			}
172→		}
173→
174→		authHandle := auth.GetAuthInstance()
175→
176→		if flagSyncLDAP {
177→			if err := syncLDAP(authHandle); err != nil {
178→				return err
179→			}
180→		}
181→
182→		if flagGenJWT != "" {
183→			if err := generateJWT(authHandle, flagGenJWT); err != nil {
184→				return err
185→			}
186→		}
187→	}
188→
189→	return nil
190→}
