202→func addUser(userSpec string) error {
203→	parts := strings.SplitN(userSpec, ":", 3)
204→	if len(parts) != 3 || len(parts[0]) == 0 {
205→		return fmt.Errorf("invalid user format, want: <username>:[admin,support,manager,api,user]:<password>, have: %s", userSpec)
206→	}
207→
208→	ur := repository.GetUserRepository()
209→	if err := ur.AddUser(&schema.User{
210→		Username: parts[0],
211→		Projects: make([]string, 0),
212→		Password: parts[2],
213→		Roles:    strings.Split(parts[1], ","),
214→	}); err != nil {
