315→func runServer(ctx context.Context) error {
316→	var wg sync.WaitGroup
317→
318→	// Initialize metric store if configuration is provided
319→	haveMetricstore := false
320→	mscfg := ccconf.GetPackageConfig("metric-store")
321→	if mscfg != nil {
322→		metrics := metricstore.BuildMetricList()
323→		metricstore.Init(mscfg, metrics, &wg)
324→
325→		// Inject repository as NodeProvider to break import cycle
326→		ms := metricstore.GetMemoryStore()
327→		jobRepo := repository.GetJobRepository()
328→		ms.SetNodeProvider(jobRepo)
329→		metricstore.MetricStoreHandle = &metricstore.InternalMetricStore{}
330→		haveMetricstore = true
331→	} else {
332→		metricstore.MetricStoreHandle = nil
333→		cclog.Debug("missing internal metricstore configuration")
334→	}
335→
336→	// Initialize external metric stores if configuration is provided
337→	mscfg = ccconf.GetPackageConfig("metric-store-external")
338→	if mscfg != nil {
339→		err := metricdispatch.Init(mscfg)
340→
341→		if err != nil {
342→			cclog.Debugf("error while initializing external metricdispatch: %v", err)
343→		} else {
344→			haveMetricstore = true
345→		}
346→	}
347→
348→	if !haveMetricstore {
349→		return fmt.Errorf("missing metricstore configuration")
350→	}
351→
352→	// Start archiver and task manager
353→	archiver.Start(repository.GetJobRepository(), ctx)
354→	taskmanager.Start(ccconf.GetPackageConfig("cron"), ccconf.GetPackageConfig("archive"))
355→
356→	// Initialize web UI
357→	cfg := ccconf.GetPackageConfig("ui")
358→	if err := web.Init(cfg); err != nil {
359→		return fmt.Errorf("initializing web UI: %w", err)
360→	}
361→
362→	// Initialize HTTP server
363→	srv, err := NewServer(version, commit, date)
364→	if err != nil {
365→		return fmt.Errorf("creating server: %w", err)
366→	}
367→
368→	// Channel to collect errors from server
369→	errChan := make(chan error, 1)
370→
371→	// Start HTTP server
372→	wg.Go(func() {
373→		if err := srv.Start(ctx); err != nil {
374→			errChan <- err
375→		}
376→	})
377→
378→	// Handle shutdown signals
379→	wg.Add(1)
380→	sigs := make(chan os.Signal, 1)
381→	signal.Notify(sigs, syscall.SIGINT, syscall.SIGTERM)
382→	go func() {
383→		defer wg.Done()
384→		select {
385→		case <-sigs:
386→			cclog.Info("Shutdown signal received")
387→		case <-ctx.Done():
388→		}
389→
390→		runtime.SystemdNotify(false, "Shutting down ...")
391→		srv.Shutdown(ctx)
392→		util.FsWatcherShutdown()
393→		taskmanager.Shutdown()
394→	}()
395→
396→	// Set GC percent if not configured
397→	if os.Getenv(envGOGC) == "" {
398→		// trigger GC when heap grows 15% above the previous live set
399→		debug.SetGCPercent(15)
400→	}
401→	runtime.SystemdNotify(true, "running")
402→
403→	waitDone := make(chan struct{})
404→	go func() {
405→		wg.Wait()
406→		close(waitDone)
407→	}()
408→
409→	go func() {
410→		<-waitDone
411→		close(errChan)
412→	}()
413→
414→	// Wait for either:
415→	// 1. An error from server startup
416→	// 2. Completion of all goroutines (normal shutdown or crash)
417→	select {
418→	case err := <-errChan:
419→		// errChan will be closed when waitDone is closed, which happens
420→		// when all goroutines complete (either from normal shutdown or error)
421→		if err != nil {
422→			return err
423→		}
424→	case <-time.After(100 * time.Millisecond):
425→		// Give the server 100ms to start and report any immediate startup errors
426→		// After that, just wait for normal shutdown completion
427→		select {
428→		case err := <-errChan:
429→			if err != nil {
430→				return err
431→			}
432→		case <-waitDone:
433→			// Normal shutdown completed
434→		}
435→	}
436→
437→	cclog.Print("Graceful shutdown completed!")
438→	return nil
439→}
440→
441→func run() error {
442→	cliInit()
443→
444→	if flagVersion {
445→		printVersion()
446→		return nil
447→	}
448→
449→	// Initialize logger
450→	cclog.Init(flagLogLevel, flagLogDateTime)
451→
452→	// Handle init flag
453→	if flagInit {
454→		initEnv()
455→		cclog.Exit("Successfully setup environment!\n" +
456→			"Please review config.json and .env and adjust it to your needs.\n" +
457→			"Add your job-archive at ./var/job-archive.")
458→	}
459→
460→	// Initialize gops agent
461→	if err := initGops(); err != nil {
462→		return err
463→	}
464→
465→	// Initialize subsystems in dependency order:
466→	// 1. Load environment variables from .env file (contains sensitive configuration)
467→	// 2. Load configuration from config.json (may reference environment variables)
468→	// 3. Handle database migration commands if requested
469→	// 4. Initialize database connection (requires config for connection string)
470→	// 5. Handle user commands if requested (requires database and authentication config)
471→	// 6. Initialize subsystems like archive and metrics (require config and database)
472→
473→	// Load environment and configuration
474→	if err := loadEnvironment(); err != nil {
475→		return err
476→	}
477→
478→	if err := initConfiguration(); err != nil {
479→		return err
480→	}
481→
482→	// Handle database migration (migrate, revert, force)
483→	if err := handleDatabaseCommands(); err != nil {
484→		return err
485→	}
486→
487→	// Initialize database
488→	if err := initDatabase(); err != nil {
489→		return err
490→	}
491→
492→	// Handle user commands (add, delete, sync, JWT)
493→	if err := handleUserCommands(); err != nil {
494→		return err
495→	}
496→
497→	// Initialize subsystems (archive, metrics, taggers)
498→	if err := initSubsystems(); err != nil {
499→		return err
500→	}
501→
502→	// Exit if start server is not requested
503→	if !flagServer {
504→		cclog.Exit("No errors, server flag not set. Exiting cc-backend.")
505→	}
506→
507→	// Run server with context
508→	ctx, cancel := context.WithCancel(context.Background())
509→	defer cancel()
510→
511→	return runServer(ctx)
512→}
513→
514→func main() {
515→	if err := run(); err != nil {
516→		cclog.Error(err.Error())
517→		os.Exit(1)
518→	}
519→}
